struct Stock: Codable, Identifiable, Hashable {
    let id: String
    let symbol: String
    let name: String
    var currentPrice: Double
    var previousClose: Double
    var change: Double {
        currentPrice - previousClose
    }
    var changePercent: Double {
        (change / previousClose) * 100
    }
}

struct Trade: Codable, Identifiable {
    let id: String
    let symbol: String
    let type: TradeType
    let quantity: Int
    let price: Double
    let timestamp: Date
    let status: TradeStatus
    
    enum TradeType: String, Codable {
        case buy, sell
    }
    
    enum TradeStatus: String, Codable {
        case pending, executed, failed, cancelled
    }
}

struct Portfolio: Codable {
    var holdings: [Holding]
    var cashBalance: Double
    var totalValue: Double {
        holdings.reduce(cashBalance) { $0 + $1.marketValue }
    }
    
    mutating func addHolding(_ holding: Holding) {
        if let index = holdings.firstIndex(where: { $0.symbol == holding.symbol }) {
            holdings[index].quantity += holding.quantity
            holdings[index].averagePrice = ((holdings[index].averagePrice * Double(holdings[index].quantity - holding.quantity)) + (holding.averagePrice * Double(holding.quantity))) / Double(holdings[index].quantity)
        } else {
            holdings.append(holding)
        }
    }
    
    mutating func removeHolding(symbol: String, quantity: Int) {
        if let index = holdings.firstIndex(where: { $0.symbol == symbol }) {
            if holdings[index].quantity <= quantity {
                holdings.remove(at: index)
            } else {
                holdings[index].quantity -= quantity
            }
        }
    }
}

struct Holding: Codable, Identifiable {
    let id: String
    let symbol: String
    var quantity: Int
    var averagePrice: Double
    var currentPrice: Double
    
    var marketValue: Double {
        Double(quantity) * currentPrice
    }
    
    var totalGainLoss: Double {
        marketValue - (averagePrice * Double(quantity))
    }
    
    var gainLossPercent: Double {
        (totalGainLoss / (averagePrice * Double(quantity))) * 100
    }
    
    init(id: String = UUID().uuidString, symbol: String, quantity: Int, averagePrice: Double, currentPrice: Double) {
        self.id = id
        self.symbol = symbol
        self.quantity = quantity
        self.averagePrice = averagePrice
        self.currentPrice = currentPrice
    }
}

